namespace BgControls.Windows.Controls;/// <summary>/// 为选项卡项更改相关的路由事件提供数据的类./// </summary>public class TabChangedEventArgs : RoutedEventArgs{    /// <summary>    /// Initializes a new instance of the <see cref="TabChangedEventArgs"/> class.    /// </summary>    /// <param name="tabItem">受影响的选项卡项.</param>    /// <param name="dataContext">选项卡项对应的数据上下文.</param>    /// <param name="routedEvent">关联的路由事件标识符. </param>    /// <param name="source">引发事件的源对象. </param>    public TabChangedEventArgs(BgTabItem tabItem, object dataContext, RoutedEvent routedEvent, object source)        : base(routedEvent, source)    {        this.TabItem = tabItem;        this.DataContext = dataContext;    }    /// <summary>    /// Gets 与此事件关联的选项卡项实例.    /// </summary>    public BgTabItem TabItem { get; private set; }    /// <summary>    /// Gets 选定选项卡项的数据上下文（DataContext）.    /// </summary>    public object DataContext { get; private set; }}